ValidationRule.errorConditionFormula:
AND(
  CONTAINS($Profile.Name,'Dealer')
 /*CONTAINS($User.License_type__c,'Partner') */
, TEXT($User.PKISuperTerritory__c) = 'EMEAI' 
, IF( TEXT($User.Sales_Region__c)='NORDICS' 
, NOT(CONTAINS('USD,EUR,DKK,NOK', TEXT(CurrencyIsoCode)))
, NOT(CONTAINS('USD,EUR', TEXT(CurrencyIsoCode)))
)
)
